# OEIS sequence: A224299

from fractions import Fraction
def A224299(n):
    if n == 0: return 0
    x = Fraction(1, 2*-n - 1)
    seen = set()
    while x not in seen:
        seen.add(x)
        x = x/2 if x.numerator % 2 == 0 else 3*x + 1
    return len(seen) - 1 - (x == 2) # _Falk Hüffner_, Mar 19 2026

